mapper.select:
SELECT s.id, s.name, s.no, s.gender, s.phone, s.id_card, s.is_college, s.address, s.degree, s.graduation_date, s.clazz_id, s.violation_count, s.violation_score, s.create_time, s.update_time, c.name AS clazz_name FROM student s LEFT JOIN clazz c ON s.clazz_id = c.id
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.gender = #{gender}
AND s.degree = #{degree}
AND s.clazz_id = #{clazzId}
ORDER BY s.update_time DESC

mapper.update:
UPDATE student
name = #{name}, no = #{no}, gender = #{gender}, phone = #{phone}, id_card = #{idCard}, is_college = #{isCollege}, address = #{address}, degree = #{degree}, graduation_date = #{graduationDate}, clazz_id = #{clazzId}, violation_count = #{violationCount}, violation_score = #{violationScore},
WHERE id = #{id}
